// FormBuilder Functional Handler Conformance Tests
//
// Auto-generated by TestGen from concept spec invariants.
// Validates StorageProgram construction, purity, variant coverage,
// read/write sets, interpreted execution, and invariant conformance.

import { describe, it, expect, beforeEach } from 'vitest';
import fc from 'fast-check';
import { formBuilderHandler } from '../../handlers/ts/app/form-builder.handler.js';
import {
  classifyPurity,
  extractCompletionVariants,
  extractReadSet,
  extractWriteSet,
  extractPerformSet,
} from '../../runtime/storage-program.js';
import { interpret } from '../../runtime/interpreter.js';
import { createInMemoryStorage } from '../../runtime/adapters/storage.js';

describe('FormBuilder functional handler', () => {
  let storage: ReturnType<typeof createInMemoryStorage>;

  beforeEach(() => {
    storage = createInMemoryStorage();
  });

  describe('buildForm', () => {
    it('builds a valid StorageProgram', () => {
      const program = formBuilderHandler.buildForm({ form: 'test', schema: 'test-schema' });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = formBuilderHandler.buildForm({ form: 'test', schema: 'test-schema' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('declares completion variants', () => {
      const program = formBuilderHandler.buildForm({ form: 'test', schema: 'test-schema' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = program.effects?.completionVariants ?? extractCompletionVariants(program);
      expect(variants.size).toBeGreaterThan(0);
    });

    it('declares read and write sets', () => {
      const program = formBuilderHandler.buildForm({ form: 'test', schema: 'test-schema' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = formBuilderHandler.buildForm({ form: 'test', schema: 'test-schema' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('executes without crashing', async () => {
      if (typeof formBuilderHandler.buildForm !== 'function') return;
      try {
        const result = await interpret(formBuilderHandler.buildForm({ form: 'test', schema: 'test-schema' }), storage);
        expect(result).toBeDefined();
        expect(result.variant).toBeDefined();
        expect(typeof result.variant).toBe('string');
      } catch (e) {
        // Handler may throw on invalid default inputs (e.g. JSON parse) — that's acceptable
        expect(e).toBeDefined();
      }
    });

  });

  describe('invariant examples', () => {
    it("buildForm then buildForm", async () => {
      const storage = createInMemoryStorage();
      const buildFormResult0 = await interpret(formBuilderHandler.buildForm({ form: {"type":"variable","name":"f"}, schema: {"type":"literal","value":"user-profile"} }), storage);
      expect(buildFormResult0.variant).toBe("ok");
      const definition = buildFormResult0.output["definition"];
      const thenResult0 = await interpret(formBuilderHandler.buildForm({ form: {"type":"variable","name":"f"}, schema: {"type":"literal","value":"user-profile"} }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: formDefinitions have required fields', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('buildForm'), input: fc.record({ form: fc.string(), schema: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = formBuilderHandler[step.action];
              if (typeof actionFn === 'function') {
                try {
                  const program = actionFn.call(formBuilderHandler, step.input as Record<string, unknown>);
                  const result = await interpret(program, storage);
                  expect(result.variant).toBeDefined();
                } catch { /* handler may throw on random inputs */ }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: orphaned entry in formDefinitions', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('buildForm'), input: fc.record({ form: fc.string(), schema: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = formBuilderHandler[step.action];
              if (typeof actionFn === 'function') {
                try {
                  const program = actionFn.call(formBuilderHandler, step.input as Record<string, unknown>);
                  const result = await interpret(program, storage);
                  expect(result.variant).toBeDefined();
                  // Never: orphaned entry in formDefinitions
                } catch { /* handler may throw on random inputs */ }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

  describe('action contracts (PBT)', () => {
    it('buildForm handles empty input: ', async () => {
      if (typeof formBuilderHandler.buildForm !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await interpret(formBuilderHandler.buildForm({  }), storage);
      expect(result).toBeDefined();
      expect(result.variant).toBeDefined();
    });

    it('buildForm ensures on ok: ', async () => {
      if (typeof formBuilderHandler.buildForm !== 'function') return;
      let seen = false;
      await fc.assert(
        fc.asyncProperty(
          fc.record({ form: fc.string(), schema: fc.string({ minLength: 1, maxLength: 50 }) }),
          async (input) => {
            const storage = createInMemoryStorage();
            const program = formBuilderHandler.buildForm(input as Record<string, unknown>);
            const result = await interpret(program, storage);
            if (result.variant === "ok") {
              seen = true;
              expect(result.output).toBeDefined();
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

});
